VALUES
  ('pukao-6f0ba476-moex-00049', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲積欠乙銀行新臺幣（下同）300萬元債務，並向甲父丙借款600萬元未清償，除此之外身無分 文。丙過世時，留下現金1800萬元，由子女甲、丁、戊繼承。甲、丁、戊協議按應繼分均分遺產。 下列敘述，何者錯誤？', '["甲可分得200萬元", "乙可因而獲償300萬元", "丁可分得遺產三分之一", "戊可自遺產分得800萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00050', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於拋棄繼承之敘述，何者正確？', '["拋棄繼承為單獨行為，未成年人得單獨為之", "拋棄繼承，應於繼承開始時起三個月內，以書面向法院為之", "因他人拋棄繼承而應為繼承之人，為拋棄繼承時，應於知悉其得繼承之日起三個月內為之", "拋棄繼承，是單獨行為，自拋棄時起發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "b84e55ea72f9", "answer_pdf_sha1": "bebb5c6f63b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00051', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'essay', '請依相關法令規定計算並回答下列問題：（計算題請詳列計算式，否則不
予計分）
甲於 114 年 5 月將座落於臺北市供自住使用之房地一處（土地面積 1
公畝）贈與其子乙，該房地產的總市價 5,000 萬元，移轉時土地公告
現值為 2,000萬元，房屋評定標準價格 400萬元，該房地產係甲於 23
年前取得，取得當時公告土地現值為 600萬元，房屋評定標準價格 500
萬元，當時房屋及土地的總市價為 2,200 萬元，甲購得土地後支付工
程受益費10 萬元，改良土地費用20 萬元，臺灣地區消費者物價總指
數為 130，試問此次贈與可否適用自用住宅用地優惠稅率課徵土地增
值稅？納稅義務人為何？需繳納多少土地增值稅？（請以對納稅義務
人最有利的方式，計算應納之土地增值稅額）（15 分）
丙為經常居住中華民國境內之中華民國國民，於 114 年有二次贈與行
為，第一次是在1 月贈與兒子丁現金 300 萬元，第二次是在 5月出資
100 萬元，無償為丁購買中華民國境內 A上市公司股票 2 萬股，並登
記為丁所有，贈與日每股開盤價52 元，每股收盤價 48 元。試問丙第
一次與第二次贈與應納之贈與稅各為多少？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00052', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'essay', '請依加值型及非加值型營業稅法及相關規定，回答下列問題：
營業人未依規定期限申報銷售額或統一發票明細表，未逾三十日者，
有關滯報金之處罰規定為何？（5 分）
適用一般稅額計算之營業人，若申報銷項稅額小於進項稅額，應如何
處理？（10分）
甲公司 114 年 3-4 月在國內銷售應稅貨物銷售額 3,600,000 元（不含
稅）、外銷1,200,000 元；當期進貨及費用6,000,000 元（不含稅），其
中包括交際費 200,000 元（不含稅）；另購置機器設備 1,500,000 元（不
含稅），均取得合法憑證。上期累積留抵稅額 10,000 元，請根據上述
資料，計算甲公司之本期應繳（應退、留抵）稅額。（請詳列計算式，
否則不予計分）（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00053', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法之規定，下列敘述何者正確？', '["個人買家向在我國境內無固定營業場所之境外網站購買線上遊戲軟體，屬於購買勞務，應課徵 營業稅，由境內買家依規定申報繳納", "美國A大學的學術研究中心透過網際網路銷售一套電子圖書資料庫給我國某大學供教學使用， 並且每年收取資料庫使用費用，屬於銷售勞務，由我國某大學負責申報繳納", "外國國際運輸事業在我國境內無固定營業場所而有營業代理人者，其在我國境內銷售勞務，應 由勞務買受人申報繳納營業稅", "乙公司為加值型營業人，購買國外勞務專供經營應稅貨物或勞務之用者，免予繳納進口營業稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00054', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依貨物稅條例之規定，下列那些貨物免徵貨物稅？①應稅貨物用作製造另一應稅貨物之原料者', '["橡膠輪胎", "合於國家標準之純天然果汁", "應稅貨物捐贈勞軍者", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00055', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依現行房屋稅條例之規定，下列敘述何者正確？', '["本人、配偶及未成年子女於全國僅持有一戶房屋，供自住且房屋現值在一定金額以下者，房屋 稅稅率為其房屋現值1%", "以土地設定地上權之使用權房屋並供該使用權人自住使用者，房屋稅稅率為其房屋現值1.5%", "房屋供直系親屬實際居住（非營業），且於該屋辦竣戶籍登記，且本人於全國房屋合計4戶，可 適用自住房屋稅稅率1.2%", "房屋同時作住家及非住家用者，非住家用之課稅面積不得超過全部面積六分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00056', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依納稅者權利保護法之規定，下列敘述何者正確？①最高行政法院及高等行政法院應設稅務專業', '["稅務案件專業法官證明書之核發標準應由經濟 部定之", "中央主管機關依訴願法設置訴願委員會之委員，其中社會公正人士、學者、專家不得 少於四分之三，並應具備法制、財政、經濟或會計之專長", "納稅者違反稅法上義務之行為非出 於故意或過失者，不予處罰", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00057', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵機關對逃漏那些稅捐，認為涉有犯罪嫌疑之案件，得聲請司法機關簽發搜索票後，會', '["所得稅", "貨物稅", "土地增值稅", "遺產及贈與稅  ⑤營業稅  ⑥印花稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00058', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-114-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依所得稅法、營利事業所得稅查核準則之規定，下列那些項目得列為營業事業之費用或損失？', '["進口關稅", "捐贈經政府登記有案之體育團體", "各種稅法規定加計之滯納利息", "依加值 型及非加值型營業稅法第 51 條規定追繳之營業稅  ⑤經營本業及附屬業務以外之費用及損失⑥ 興建固定資產之借款，於建築完成後支付之利息"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:44+00:00", "source_pdf_sha1": "0ef05e480f83", "answer_pdf_sha1": "c48556124cab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
